template <typename Key, typename Value, typename Hash = std::hash<Key>>
class ThreadSafeHashTable {
public:
    explicit ThreadSafeHashTable(size_t numBuckets = 16, size_t numLocks = 4)
        : buckets(numBuckets), locks(numLocks) {}

    void insert(const Key& key, const Value& value) {
        auto& bucket = getBucket(key);
        std::unique_lock lock(locks[hashKey(key) % locks.size()]);
        for (auto& [k, v] : bucket) {
            if (k == key) {
                v = value;
                return;
            }
        }
        bucket.emplace_back(key, value);
    }

    std::optional<Value> find(const Key& key) const {
        auto& bucket = getBucket(key);
        std::shared_lock lock(locks[hashKey(key) % locks.size()]);
        for (const auto& [k, v] : bucket) {
            if (k == key) {
                return v;
            }
        }
        return std::nullopt;
    }

    void remove(const Key& key) {
        auto& bucket = getBucket(key);
        std::unique_lock lock(locks[hashKey(key) % locks.size()]);
        bucket.remove_if([&key](const auto& pair) { return pair.first == key; });
    }

private:
    using Bucket = std::list<std::pair<Key, Value>>;
    std::vector<Bucket> buckets;
    mutable std::vector<std::shared_mutex> locks;
    Hash hashKey;

    Bucket& getBucket(const Key& key) {
        return buckets[hashKey(key) % buckets.size()];
    }

    const Bucket& getBucket(const Key& key) const {
        return buckets[hashKey(key) % buckets.size()];
    }
};

