import java.time.LocalDateTime;
import java.time.OffsetDateTime;
import java.time.ZoneOffset;
import java.time.ZonedDateTime;
import java.time.format.DateTimeFormatter;
public class TimezoneConverter {
    public static String convertToUTC(String localDate, String localTime, String timezoneOffset) {
        LocalDateTime localDateTime = LocalDateTime.parse(localDate + "T" + localTime);
        ZoneOffset offset = ZoneOffset.of(fixOffsetFormat(timezoneOffset));
        OffsetDateTime offsetDateTime = localDateTime.atOffset(offset);
        ZonedDateTime utcDateTime = offsetDateTime.toZonedDateTime().withZoneSameInstant(ZoneOffset.UTC);
        return utcDateTime.format(DateTimeFormatter.ofPattern("yyyy-MM-dd HH:mm:ss"));
    }
    private static String fixOffsetFormat(String offset) {
        if (!offset.matches("^[+-]\\d{2}:\\d{2}$")) {
            return "+00:00"; 
        }
        return offset;
    }
    public static void main(String[] args) {
        String date = "2023-04-01";
        String time = "15:00:00";
        String offset = "+05:30"; 
        String utcTime = convertToUTC(date, time, offset);
        System.out.println("UTC时间: " + utcTime);
        String expectedUTC = "2023-04-01 09:30:00";
        assert utcTime.equals(expectedUTC) : "转换结果不正确";
    }
}

